import urllib.request,urllib.error,json,sys,time
K=sys.argv[1]
# 1) дашборд-вебхук
try:
    r=urllib.request.urlopen('https://irynakarmazina.app.n8n.cloud/webhook/crm-dashboard',timeout=45)
    b=r.read(); ishtml=b[:60].lower().find(b'<!doctype')>=0 or b[:200].lower().find(b'<html')>=0
    print('ДАШБОРД: HTTP',r.status,'| байт',len(b),'| HTML:',ishtml)
except urllib.error.HTTPError as e:
    print('ДАШБОРД HTTP',e.code,'| body:',e.read()[:200].decode('utf-8','ignore'))
except Exception as e:
    print('ДАШБОРД ERR',e)
# 2) остання помилка виконання (чи вже не limit)
B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def GET(w):
    for a in range(5):
        try: return json.load(urllib.request.urlopen(urllib.request.Request(B+w,headers={'X-N8N-API-KEY':K}),timeout=15))
        except Exception: time.sleep(3)
    return None
ex=GET('executions?workflowId=1YdXnLFOXI85IsWv&limit=1&includeData=true')
data=ex.get('data') if isinstance(ex,dict) else ex
if data:
    e=data[0]; rd=((e.get('data') or {}).get('resultData') or {}); err=rd.get('error')
    print('останнє викон дашборда: status',e.get('status'),'| помилка:', (json.dumps(err)[:120] if err else 'немає'))

PYEOF
